#!/usr/bin/env perl

use strict;
use warnings;

my $comment = param('comment');

if (defined($comment)) {
    print "Content-type: text/html\n\n";
    print "<div>$comment</div>";
} else {
    print "Content-type: text/plain\n\n";
    print "Error: No comment provided.";
}